 * Finds the peak element (the turning point) in a bitonic array.
 * @param {number[]} nums - The bitonic array.
 * @returns {number} The index of the peak element.
 */
function findPeakIndex(nums) {
    let n = nums.length;
    let left = 0;
    let right = n - 1;

    // Since it's guaranteed to be bitonic with at least 3 elements, 
    // a standard binary search approach for peak finding works.
    while (left < right) {
        const mid = Math.floor((left + right) / 2);

        // If the element at mid is smaller than the element to its right, 
        // the peak must be to the right (including mid+1).
        if (nums[mid] < nums[mid + 1]) {
            left = mid + 1;
        } else {
            // Otherwise, the peak is at mid or to the left of mid.
            right = mid;
        }
    }
    return left; // left == right == peak index
